1	/**
2	 * Pointer interaction handlers for the piano roll canvas.
3	 * Manages draw, select, move, resize, erase, and lasso operations.
4	 * Pushes undo commands on completion.
5	 */
6	import { useCallback, useRef, useState } from "react";
7	import { useDawStore } from "@state/store";
8	import type { MIDINoteEvent } from "@state/track/types";
9	import { isMidiClip } from "@state/track/types";
10	import { sharedUndoManager } from "@state/undo";
11	import type { UndoCommand } from "@state/undo/undo-command";
12	import {
13	  AddNoteCommand,
14	  RemoveNoteCommand,
15	  MoveNoteCommand,
16	  ResizeNoteCommand,
17	  BatchNoteCommand,
18	} from "@state/track/midi-commands";
19	import type { PianoRollViewState, PianoRollTool } from "./piano-roll-renderer";
20	import {
21	  pianoRollHitTest,
22	  xToSeconds,
23	  yToPitch,
24	  pianoRollSnapToGrid,
25	  lassoSelectNotes,
26	  type PianoRollGridSnap,
27	} from "./piano-roll-hit-test";
28	import { PR_VELOCITY_LANE_HEIGHT } from "./constants";
29	
30	type DragState =
31	  | { kind: "idle" }
32	  | {
33	      kind: "move-note";
34	      noteId: string;
35	      clipId: string;
36	      startX: number;
37	      startY: number;
38	      origStartTime: number;
39	      origPitch: number;
40	    }
41	  | {
42	      kind: "resize-note";
43	      noteId: string;
44	      clipId: string;
45	      startX: number;
46	      origStartTime: number;
47	      origDuration: number;
48	      edge: "left" | "right";
49	    }
50	  | {
51	      kind: "draw-note";
52	      clipId: string;
53	      noteId: string;
54	      startTime: number;
55	      pitch: number;
56	    }
57	  | { kind: "rubber-band"; startX: number; startY: number };
58	
59	export type PianoRollInteractions = {
60	  cursor: string;
61	  onPointerDown: (e: React.PointerEvent<HTMLCanvasElement>) => void;
62	  onPointerMove: (e: React.PointerEvent<HTMLCanvasElement>) => void;
63	  onPointerUp: (e: React.PointerEvent<HTMLCanvasElement>) => void;
64	  deleteSelectedNotes: () => void;
65	};
66	
67	let noteCounter = 0;
68	function generateNoteId(): string {
69	  noteCounter += 1;
70	  return `note-${String(Date.now())}-${String(noteCounter)}`;
71	}
72	
73	function gridDuration(bpm: number, snap: PianoRollGridSnap): number {
74	  const secPerBeat = 60 / bpm;
75	  switch (snap) {
76	    case "1/4":
77	      return secPerBeat;
78	    case "1/8":
79	      return secPerBeat / 2;
80	    case "1/16":
81	      return secPerBeat / 4;
82	    case "1/8T":
83	      return secPerBeat / 3;
84	    case "1/16T":
85	      return secPerBeat / 6;
86	  }
87	}
88	
89	export function usePianoRollInteractions(
90	  clipId: string | null,
91	  view: PianoRollViewState,
92	  tool: PianoRollTool,
93	  gridSnap: PianoRollGridSnap,
94	  onNotePreview?: (note: number, velocity: number) => void,
95	  onNotePreviewEnd?: (note: number) => void,
96	): PianoRollInteractions {
97	  const dragRef = useRef<DragState>({ kind: "idle" });
98	  const [cursor, setCursor] = useState(
99	    clipId !== null && tool === "pencil" ? "crosshair" : "default",
100	  );
101	
102	  const getCanvasPos = useCallback(
103	    (e: React.MouseEvent<HTMLCanvasElement>): { x: number; y: number } => {
104	      const rect = e.currentTarget.getBoundingClientRect();
105	      return { x: e.clientX - rect.left, y: e.clientY - rect.top };
106	    },
107	    [],
108	  );
109	
110	  const getNotes = useCallback((): readonly MIDINoteEvent[] => {
111	    if (clipId === null) return [];
112	    const clip = useDawStore.getState().clips[clipId];
113	    if (clip === undefined || !isMidiClip(clip)) return [];
114	    return clip.noteEvents;
115	  }, [clipId]);
116	
117	  const onPointerDown = useCallback(
118	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
119	      if (clipId === null) return;
120	
121	      const { x, y } = getCanvasPos(e);
122	      const state = useDawStore.getState();
123	      const notes = getNotes();
124	      const canvasHeight = e.currentTarget.getBoundingClientRect().height;
125	      const hit = pianoRollHitTest(
126	        x,
127	        y,
128	        view,
129	        notes,
130	        canvasHeight,
131	        PR_VELOCITY_LANE_HEIGHT,
132	      );
133	
134	      switch (tool) {
135	        case "pencil": {
136	          if (hit.kind === "empty-grid") {
137	            const snappedTime = pianoRollSnapToGrid(
138	              hit.timeSeconds,
139	              state.bpm,
140	              gridSnap,
141	            );
142	            const dur = gridDuration(state.bpm, gridSnap);
143	            const noteId = generateNoteId();
144	            const note: MIDINoteEvent = {
145	              id: noteId,
146	              pitch: hit.pitch,
147	              velocity: 100,
148	              startTime: Math.max(0, snappedTime),
149	              duration: dur,
150	            };
151	            const cmd = new AddNoteCommand(clipId, note);
152	            cmd.execute();
153	            sharedUndoManager.push(cmd);
154	            onNotePreview?.(note.pitch, note.velocity);
155	
156	            e.currentTarget.setPointerCapture(e.pointerId);
157	            dragRef.current = {
158	              kind: "draw-note",
159	              clipId,
160	              noteId,
161	              startTime: note.startTime,
162	              pitch: note.pitch,
163	            };
164	          }
165	          break;
166	        }
167	        case "select": {
168	          if (hit.kind === "note-body") {
169	            if (e.shiftKey) {
170	              const current = [...state.selectedNoteIds];
171	              const idx = current.indexOf(hit.noteId);
172	              if (idx >= 0) {
173	                current.splice(idx, 1);
174	              } else {
175	                current.push(hit.noteId);
176	              }
177	              state.setSelectedNoteIds(current);
178	            } else {
179	              if (!state.selectedNoteIds.includes(hit.noteId)) {
180	                state.setSelectedNoteIds([hit.noteId]);
181	              }
182	            }
183	
184	            // Find note for drag
185	            const note = notes.find((n) => n.id === hit.noteId);
186	            if (note !== undefined) {
187	              e.currentTarget.setPointerCapture(e.pointerId);
188	              dragRef.current = {
189	                kind: "move-note",
190	                noteId: hit.noteId,
191	                clipId,
192	                startX: x,
193	                startY: y,
194	                origStartTime: note.startTime,
195	                origPitch: note.pitch,
196	              };
197	            }
198	          } else if (
199	            hit.kind === "note-left-edge" ||
200	            hit.kind === "note-right-edge"
201	          ) {
202	            state.setSelectedNoteIds([hit.noteId]);
203	            const note = notes.find((n) => n.id === hit.noteId);
204	            if (note !== undefined) {
205	              e.currentTarget.setPointerCapture(e.pointerId);
206	              dragRef.current = {
207	                kind: "resize-note",
208	                noteId: hit.noteId,
209	                clipId,
210	                startX: x,
211	                origStartTime: note.startTime,
212	                origDuration: note.duration,
213	                edge: hit.kind === "note-left-edge" ? "left" : "right",
214	              };
215	            }
216	          } else if (hit.kind === "empty-grid") {
217	            if (!e.shiftKey) {
218	              state.setSelectedNoteIds([]);
219	            }
220	            e.currentTarget.setPointerCapture(e.pointerId);
221	            dragRef.current = { kind: "rubber-band", startX: x, startY: y };
222	          }
223	          break;
224	        }
225	        case "erase": {
226	          if (
227	            hit.kind === "note-body" ||
228	            hit.kind === "note-left-edge" ||
229	            hit.kind === "note-right-edge"
230	          ) {
231	            const cmd = new RemoveNoteCommand(clipId, hit.noteId);
232	            cmd.execute();
233	            sharedUndoManager.push(cmd);
234	          }
235	          break;
236	        }
237	      }
238	    },
239	    [clipId, view, tool, gridSnap, getCanvasPos, getNotes, onNotePreview],
240	  );
241	
242	  const onPointerMove = useCallback(
243	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
244	      const { x, y } = getCanvasPos(e);
245	      const drag = dragRef.current;
246	      const state = useDawStore.getState();
247	
248	      if (drag.kind === "idle") {
249	        // Update cursor based on hover
250	        if (clipId === null) {
251	          setCursor("default");
252	          return;
253	        }
254	
255	        const notes = getNotes();
256	        const canvasHeight = e.currentTarget.getBoundingClientRect().height;
257	        const hit = pianoRollHitTest(
258	          x,
259	          y,
260	          view,
261	          notes,
262	          canvasHeight,
263	          PR_VELOCITY_LANE_HEIGHT,
264	        );
265	
266	        if (tool === "pencil") {
267	          setCursor("crosshair");
268	        } else if (tool === "select") {
269	          switch (hit.kind) {
270	            case "note-body":
271	              setCursor("pointer");
272	              break;
273	            case "note-left-edge":
274	            case "note-right-edge":
275	              setCursor("ew-resize");
276	              break;
277	            default:
278	              setCursor("default");
279	              break;
280	          }
281	        } else {
282	          setCursor("default");
283	        }
284	        return;
285	      }
286	
287	      switch (drag.kind) {
288	        case "move-note": {
289	          setCursor("grabbing");
290	          const deltaPx = x - drag.startX;
291	          const deltaSec = deltaPx / view.pixelsPerSecond;
292	          const newTime = pianoRollSnapToGrid(
293	            Math.max(0, drag.origStartTime + deltaSec),
294	            state.bpm,
295	            gridSnap,
296	          );
297	          const newPitch = yToPitch(y, view);
298	          state.moveNoteEvent(drag.clipId, drag.noteId, newTime, newPitch);
299	          break;
300	        }
301	        case "resize-note": {
302	          setCursor("ew-resize");
303	          const deltaPx = x - drag.startX;
304	          const deltaSec = deltaPx / view.pixelsPerSecond;
305	          if (drag.edge === "left") {
306	            const origEnd = drag.origStartTime + drag.origDuration;
307	            const newStartTime = Math.max(
308	              0,
309	              Math.min(drag.origStartTime + deltaSec, origEnd - 0.01),
310	            );
311	            const newDuration = origEnd - newStartTime;
312	            state.moveNoteEvent(
313	              drag.clipId,
314	              drag.noteId,
315	              newStartTime,
316	              // Keep pitch unchanged -- look up current pitch
317	              getNotes().find((n) => n.id === drag.noteId)?.pitch ?? 0,
318	            );
319	            state.resizeNoteEvent(drag.clipId, drag.noteId, newDuration);
320	          } else {
321	            const newDuration = Math.max(0.01, drag.origDuration + deltaSec);
322	            state.resizeNoteEvent(drag.clipId, drag.noteId, newDuration);
323	          }
324	          break;
325	        }
326	        case "draw-note": {
327	          // Extend note duration as user drags
328	          const currentTime = xToSeconds(x, view);
329	          const snappedEnd = pianoRollSnapToGrid(
330	            currentTime,
331	            state.bpm,
332	            gridSnap,
333	          );
334	          const newDuration = Math.max(
335	            gridDuration(state.bpm, gridSnap),
336	            snappedEnd - drag.startTime,
337	          );
338	          state.resizeNoteEvent(drag.clipId, drag.noteId, newDuration);
339	          break;
340	        }
341	        case "rubber-band": {
342	          if (clipId === null) break;
343	          const notes = getNotes();
344	          const selected = lassoSelectNotes(
345	            drag.startX,
346	            drag.startY,
347	            x,
348	            y,
349	            view,
350	            notes,
351	          );
352	          state.setSelectedNoteIds([...selected]);
353	          break;
354	        }
355	      }
356	    },
357	    [clipId, view, tool, gridSnap, getCanvasPos, getNotes],
358	  );
359	
360	  const onPointerUp = useCallback(
361	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
362	      const drag = dragRef.current;
363	
364	      if (drag.kind === "move-note") {
365	        const notes = getNotes();
366	        const note = notes.find((n) => n.id === drag.noteId);
367	        if (
368	          note !== undefined &&
369	          (note.startTime !== drag.origStartTime ||
370	            note.pitch !== drag.origPitch)
371	        ) {
372	          const cmd = new MoveNoteCommand(
373	            drag.clipId,
374	            drag.noteId,
375	            note.startTime,
376	            note.pitch,
377	            drag.origStartTime,
378	            drag.origPitch,
379	          );
380	          // Store is already updated during drag -- just record for undo
381	          sharedUndoManager.push(cmd);
382	        }
383	      } else if (drag.kind === "resize-note") {
384	        const notes = getNotes();
385	        const note = notes.find((n) => n.id === drag.noteId);
386	        if (note !== undefined) {
387	          if (drag.edge === "left") {
388	            // Left-edge drag changed both startTime and duration
389	            const cmds: UndoCommand[] = [];
390	            if (note.startTime !== drag.origStartTime) {
391	              cmds.push(
392	                new MoveNoteCommand(
393	                  drag.clipId,
394	                  drag.noteId,
395	                  note.startTime,
396	                  note.pitch,
397	                  drag.origStartTime,
398	                  note.pitch,
399	                ),
400	              );
401	            }
402	            if (note.duration !== drag.origDuration) {
403	              cmds.push(
404	                new ResizeNoteCommand(
405	                  drag.clipId,
406	                  drag.noteId,
407	                  note.duration,
408	                  drag.origDuration,
409	                ),
410	              );
411	            }
412	            if (cmds.length > 0) {
413	              const batch = new BatchNoteCommand(cmds);
414	              sharedUndoManager.push(batch);
415	            }
416	          } else if (note.duration !== drag.origDuration) {
417	            const cmd = new ResizeNoteCommand(
418	              drag.clipId,
419	              drag.noteId,
420	              note.duration,
421	              drag.origDuration,
422	            );
423	            sharedUndoManager.push(cmd);
424	          }
425	        }
426	      } else if (drag.kind === "draw-note") {
427	        // If the user dragged to extend the note, capture a resize command
428	        // so redo restores the final dragged duration (not the initial grid-step size)
429	        const notes = getNotes();
430	        const note = notes.find((n) => n.id === drag.noteId);
431	        if (note !== undefined) {
432	          const state = useDawStore.getState();
433	          const initialDuration = gridDuration(state.bpm, gridSnap);
434	          if (note.duration !== initialDuration) {
435	            const cmd = new ResizeNoteCommand(
436	              drag.clipId,
437	              drag.noteId,
438	              note.duration,
439	              initialDuration,
440	            );
441	            sharedUndoManager.push(cmd);
442	          }
443	        }
444	        onNotePreviewEnd?.(drag.pitch);
445	      }
446	
447	      if (drag.kind !== "idle") {
448	        e.currentTarget.releasePointerCapture(e.pointerId);
449	      }
450	      dragRef.current = { kind: "idle" };
451	
452	      // Restore tool-appropriate cursor
453	      if (tool === "pencil") {
454	        setCursor("crosshair");
455	      } else {
456	        setCursor("default");
457	      }
458	    },
459	    [tool, gridSnap, getNotes, onNotePreviewEnd],
460	  );
461	
462	  const deleteSelectedNotes = useCallback((): void => {
463	    if (clipId === null) return;
464	    const state = useDawStore.getState();
465	    const selected = state.selectedNoteIds;
466	    if (selected.length === 0) return;
467	
468	    const commands = selected.map(
469	      (noteId) => new RemoveNoteCommand(clipId, noteId),
470	    );
471	    const batch = new BatchNoteCommand(commands);
472	    batch.execute();
473	    sharedUndoManager.push(batch);
474	    state.setSelectedNoteIds([]);
475	  }, [clipId]);
476	
477	  return {
478	    cursor,
479	    onPointerDown,
480	    onPointerMove,
481	    onPointerUp,
482	    deleteSelectedNotes,
483	  };
484	}
