452	      const clampedDuration = Math.max(0.01, newDuration);
453	      const updated: MidiClipModel = {
454	        ...clip,
455	        noteEvents: clip.noteEvents.map((n) =>
456	          n.id === noteId ? { ...n, duration: clampedDuration } : n,
