1	import { useCallback, useRef, useState } from "react";
2	
3	type DragHandlers = {
4	  onDragEnter: (e: React.DragEvent<HTMLElement>) => void;
5	  onDragOver: (e: React.DragEvent<HTMLElement>) => void;
6	  onDragLeave: (e: React.DragEvent<HTMLElement>) => void;
7	  onDrop: (e: React.DragEvent<HTMLElement>) => void;
8	};
9	
10	type UseFileDropReturn = {
11	  isDragging: boolean;
12	  handlers: DragHandlers;
13	};
14	
15	export function useFileDrop(
16	  onFiles: (files: File[]) => void,
17	): UseFileDropReturn {
18	  const [isDragging, setIsDragging] = useState(false);
19	  const dragCounter = useRef(0);
20	
21	  const onDragEnter = useCallback((e: React.DragEvent<HTMLElement>) => {
22	    e.preventDefault();
23	    dragCounter.current++;
24	    setIsDragging(true);
25	  }, []);
26	
27	  const onDragOver = useCallback((e: React.DragEvent<HTMLElement>) => {
28	    e.preventDefault();
29	  }, []);
30	
31	  const onDragLeave = useCallback((e: React.DragEvent<HTMLElement>) => {
32	    e.preventDefault();
33	    dragCounter.current--;
34	    if (dragCounter.current <= 0) {
35	      dragCounter.current = 0;
36	      setIsDragging(false);
37	    }
38	  }, []);
39	
40	  const onDrop = useCallback(
41	    (e: React.DragEvent<HTMLElement>) => {
42	      e.preventDefault();
43	      e.stopPropagation();
44	      dragCounter.current = 0;
45	      setIsDragging(false);
46	      const files = Array.from(e.dataTransfer.files);
47	      onFiles(files);
48	    },
49	    [onFiles],
50	  );
51	
52	  return {
53	    isDragging,
54	    handlers: { onDragEnter, onDragOver, onDragLeave, onDrop },
55	  };
56	}
