1	import { useCallback, useEffect, useRef, useState } from "react";
2	import { useDawStore } from "@state/store";
3	import { SynthEditor } from "@ui/synth";
4	import { DrumMachinePanel } from "@ui/drum-machine";
5	import {
6	  createStepSequencer,
7	  type StepSequencer,
8	} from "@audio/drum-machine/step-sequencer";
9	import { useTransport } from "@audio/use-transport";
10	import {
11	  DRUM_INSTRUMENTS,
12	  DEFAULT_INSTRUMENT_PARAMS,
13	  type DrumInstrumentId,
14	  type DrumInstrumentParams,
15	  type DrumPattern,
16	} from "@audio/drum-machine/drum-types";
17	import styles from "./panels.module.css";
18	
19	// Module-level caches: preserve state across unmount/remount cycles
20	export const sequencerCache = new Map<string, StepSequencer>();
21	export const paramsCache = new Map<
22	  string,
23	  Record<DrumInstrumentId, DrumInstrumentParams>
24	>();
25	
26	// Clean up caches when tracks are removed or replaced
27	let prevTrackIds = new Set(useDawStore.getState().tracks.map((t) => t.id));
28	useDawStore.subscribe((state) => {
29	  const trackIds = new Set(state.tracks.map((t) => t.id));
30	  for (const id of prevTrackIds) {
31	    if (!trackIds.has(id)) {
32	      sequencerCache.delete(id);
33	      paramsCache.delete(id);
34	    }
35	  }
36	  prevTrackIds = trackIds;
37	});
38	
39	function getOrCreateSequencer(trackId: string): StepSequencer {
40	  let seq = sequencerCache.get(trackId);
41	  if (!seq) {
42	    seq = createStepSequencer(() => {
43	      // Trigger callback - audio playback handled separately
44	    });
45	    sequencerCache.set(trackId, seq);
46	  }
47	  return seq;
48	}
49	
50	function getOrCreateParams(
51	  trackId: string,
52	): Record<DrumInstrumentId, DrumInstrumentParams> {
53	  let cached = paramsCache.get(trackId);
54	  if (!cached) {
55	    cached = {} as Record<DrumInstrumentId, DrumInstrumentParams>;
56	    for (const inst of DRUM_INSTRUMENTS) {
57	      cached[inst.id] = { ...DEFAULT_INSTRUMENT_PARAMS[inst.id] };
58	    }
59	    paramsCache.set(trackId, cached);
60	  }
61	  return cached;
62	}
63	
64	function useDrumMachineState(trackId: string): {
65	  pattern: DrumPattern;
66	  currentStep: number;
67	  params: Record<DrumInstrumentId, DrumInstrumentParams>;
68	  onToggleStep: (instrumentId: DrumInstrumentId, stepIndex: number) => void;
69	  onSetAccent: (stepIndex: number, accent: boolean) => void;
70	  onTriggerPad: (instrumentId: DrumInstrumentId) => void;
71	  onParamChange: (
72	    instrumentId: DrumInstrumentId,
73	    key: keyof DrumInstrumentParams,
74	    value: number,
75	  ) => void;
76	  onSwitchPattern: (name: string) => void;
77	  onClearPattern: () => void;
78	} {
79	  const transport = useTransport();
80	  const transportState = useDawStore((s) => s.transportState);
81	  const bpm = useDawStore((s) => s.bpm);
82	
83	  const seq = getOrCreateSequencer(trackId);
84	
85	  const [pattern, setPattern] = useState<DrumPattern>(() => seq.getPattern());
86	  const [liveStep, setLiveStep] = useState(0);
87	  const [params, setParams] = useState<
88	    Record<DrumInstrumentId, DrumInstrumentParams>
89	  >(() => getOrCreateParams(trackId));
90	
91	  // Sync pattern when trackId changes (sequencer instance changes)
92	  useEffect(() => {
93	    setPattern(seq.getPattern());
94	  }, [seq]);
95	
96	  // Transport sync: advance step indicator when playing
97	  const rafRef = useRef(0);
98	  useEffect(() => {
99	    if (transportState !== "playing") return;
100	
101	    const clock = transport.getClock();
102	    if (!clock) return;
103	
104	    const stepsPerBeat = 4; // 16th notes
105	    let lastStep = -1;
106	
107	    const tick = (): void => {
108	      const cursor = clock.getCursorSeconds();
109	      const stepDuration = 60 / (bpm * stepsPerBeat);
110	      const step = Math.floor(cursor / stepDuration) % pattern.steps.length;
111	      if (step !== lastStep) {
112	        lastStep = step;
113	        setLiveStep(step);
114	      }
115	      rafRef.current = requestAnimationFrame(tick);
116	    };
117	    rafRef.current = requestAnimationFrame(tick);
118	
119	    return () => {
120	      cancelAnimationFrame(rafRef.current);
121	    };
122	  }, [transportState, transport, bpm, pattern.steps.length]);
123	
124	  // Derive currentStep: 0 when stopped, liveStep when playing/paused
125	  const currentStep = transportState === "stopped" ? 0 : liveStep;
126	
127	  const onToggleStep = useCallback(
128	    (instrumentId: DrumInstrumentId, stepIndex: number) => {
129	      seq.toggleStep(instrumentId, stepIndex);
130	      setPattern(seq.getPattern());
131	    },
132	    [seq],
133	  );
134	
135	  const onSetAccent = useCallback(
136	    (stepIndex: number, accent: boolean) => {
137	      seq.setAccent(stepIndex, accent);
138	      setPattern(seq.getPattern());
139	    },
140	    [seq],
141	  );
142	
143	  // TODO: wire to audio engine for pad preview
144	  const onTriggerPad = useCallback((_instrumentId: DrumInstrumentId) => {}, []);
145	
146	  // TODO: propagate param changes to audio engine
147	  const onParamChange = useCallback(
148	    (
149	      instrumentId: DrumInstrumentId,
150	      key: keyof DrumInstrumentParams,
151	      value: number,
152	    ) => {
153	      setParams((prev) => {
154	        const next = {
155	          ...prev,
156	          [instrumentId]: { ...prev[instrumentId], [key]: value },
157	        };
158	        paramsCache.set(trackId, next);
159	        return next;
160	      });
161	    },
162	    [trackId],
163	  );
164	
165	  const onSwitchPattern = useCallback(
166	    (name: string) => {
167	      seq.switchPattern(name);
168	      setPattern(seq.getPattern());
169	    },
170	    [seq],
171	  );
172	
173	  const onClearPattern = useCallback(() => {
174	    seq.clearPattern();
175	    setPattern(seq.getPattern());
176	  }, [seq]);
177	
178	  return {
179	    pattern,
180	    currentStep,
181	    params,
182	    onToggleStep,
183	    onSetAccent,
184	    onTriggerPad,
185	    onParamChange,
186	    onSwitchPattern,
187	    onClearPattern,
188	  };
189	}
190	
191	function DrumMachineController({
192	  trackId,
