131	      const note = clip.noteEvents.find((n) => n.id === this.noteId);
132	      if (note && this.oldDuration === undefined) {
133	        this.oldDuration = note.duration;
134	      }
135	    }
136	    getStore().resizeNoteEvent(this.clipId, this.noteId, this.newDuration);
137	  }
138	
139	  undo(): void {
140	    getStore().resizeNoteEvent(this.clipId, this.noteId, this.oldDuration ?? 0);
141	  }
142	
143	  serialize(): Record<string, unknown> {
144	    return {
145	      clipId: this.clipId,
146	      noteId: this.noteId,
147	      newDuration: this.newDuration,
148	      oldDuration: this.oldDuration ?? 0,
149	    };
150	  }

