17	function formatError(error: MediaPoolError): string {
18	  switch (error.kind) {
19	    case "decode-failed":
20	      return `Failed to decode "${error.fileName}". Try WAV, MP3, OGG, or FLAC format.`;
21	    case "unsupported-format":
22	      return `Unsupported format: "${error.fileName}". Try WAV, MP3, OGG, or FLAC.`;
23	    case "file-too-large":
24	      return `File "${error.fileName}" is too large (max 500MB).`;
25	    case "storage-full":
26	      return `Storage full. Cannot import "${error.fileName}".`;
27	  }
28	}
