  useTransportShortcuts(registry, shortcuts);
  useSessionShortcuts(
    registry,
    shortcuts,
    undoManager,
    stableSaveNow,
    showToast,
  );

  useEffect(() => {
    registry.register({
      id: "app.shortcuts-legend",
      label: "Toggle Keyboard Shortcuts",
      execute: () => {
        setShortcutsOpen((prev) => !prev);
      },
    });
    shortcuts.bind({
      key: "?",
      shift: true,
      commandId: "app.shortcuts-legend",
    });
    return () => {
      registry.unregister("app.shortcuts-legend");
      shortcuts.unbind("app.shortcuts-legend");
    };
  }, [registry, shortcuts]);

  useKeyboardShortcuts(registry, shortcuts);

  return (
    <div
      data-testid="daw-shell"
      style={{
        display: "flex",
        flexDirection: "column",
        height: "100vh",
        backgroundColor: "var(--color-black)",
      }}
    >
      <Toolbar />
      <ErrorBoundary fallbackLabel="Panel crashed">
        <div
          style={{
            display: "flex",
            flexDirection: "column",
            flex: 1,
            overflow: "hidden",
          }}
        >
          <ArrangementPanel />
          <MixerPanel />
          <div style={{ display: "flex", overflow: "hidden" }}>
            <div style={{ flex: 1 }}>
              <InstrumentPanel />
            </div>
            <div style={{ flex: 1 }}>
              <MediaPoolPanel pool={pool} />
            </div>
          </div>
        </div>
      </ErrorBoundary>
      <KeyboardShortcutsPanel
        open={shortcutsOpen}
        onClose={() => {
          setShortcutsOpen(false);
        }}
      />
      <RecoveryDialog
        open={showRecovery}
        warnings={recoveryWarnings}
        onAccept={() => {
          setDismissed(true);
        }}
        onDiscard={() => {
          hydrateStore(createDefaultSession());
          setDismissed(true);
        }}
      />
      <ActionToast message={toastMessage} />
    </div>
  );
}

