        case "move-clip": {
          setCursor("grabbing");
          const deltaPx = x - drag.startX;
          const deltaSec = deltaPx / view.pixelsPerSecond;
          const newTime = snapToGrid(
            Math.max(0, drag.startTime + deltaSec),
            state.bpm,
            gridSnap,
